target triple = "aarch64"

define <2 x i32> @test_and(<2 x i32> %a, i1 %cond) {
entry:
  br i1 %cond, label %if.then, label %if.else

if.then:
  br label %if.end

if.else:
  br label %if.end

if.end:
  %phi1 = phi <2 x i32> [ %a, %if.then ], [ zeroinitializer, %if.else ]
  %phi2 = phi <2 x i1> [ <i1 true, i1 true>, %if.then ], [ <i1 false, i1 false>, %if.else ]
  %zext = zext <2 x i1> %phi2 to <2 x i32>
  %and = and <2 x i32> %zext, %phi1
  ret <2 x i32> %and
}
